import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const b=JSON.parse('{"title":"FPS转数快","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/fps.md","filePath":"zh-CN/deposit/fps.md"}'),o={name:"deposit/fps.md"};function i(l,t,s,n,h,p){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="fps转数快" tabindex="-1">FPS转数快 <a class="header-anchor" href="#fps转数快" aria-label="Permalink to &quot;FPS转数快&quot;">​</a></h1><p>FPS 转数快（Faster Payment System）是香港金融管理局推出的快速支付系统，支持即时跨行转账、365×24×7 全天候服务，通过 FPS 识别码付款，无需绑定手机号或电邮。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>港元（HKD）</td></tr><tr><td>到账时间</td><td>港股交易日（周一 09:00 — 周五 23:59）2 小时内；其他时段下一港股交易日 09:40 前</td></tr><tr><td>手续费</td><td>长桥免费；大部分银行免费，个别机构可能收费，请向银行确认</td></tr><tr><td>转账限额</td><td>长桥无限额，请留意银行端限额</td></tr></tbody></table><h2 id="收款信息" tabindex="-1">收款信息 <a class="header-anchor" href="#收款信息" aria-label="Permalink to &quot;收款信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>FPS ID</th><th>收款银行</th><th>收款人名称</th></tr></thead><tbody><tr><td>169152691</td><td>中国工商银行（亚洲）</td><td>Long Bridge HK Limited</td></tr><tr><td>122366339</td><td>星展银行（香港）有限公司</td><td>Long Bridge HK Limited</td></tr></tbody></table><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><ol><li>打开长桥 App，进入<strong>资产 → 存入资金</strong>，选择港元，选择银行卡，点击「FPS 转数快」，复制 FPS ID</li><li>登录网上银行或储值支付工具，通过 FPS 转数快功能向该 FPS ID 发起转账</li><li>转账完成后<strong>立即</strong>返回长桥 App，进入<strong>资产 → 存入资金 → FPS 转数快</strong>，上传汇款转账凭证</li></ol><blockquote><p>凭证必须在转账后立即上传，否则影响入金进度。</p></blockquote><h2 id="各银行操作指引" tabindex="-1">各银行操作指引 <a class="header-anchor" href="#各银行操作指引" aria-label="Permalink to &quot;各银行操作指引&quot;">​</a></h2><p>长桥 App 入金页面提供汇丰银行、工银亚洲、招行香港、众安银行等银行的详细步骤，选择对应银行后查看。</p><h2 id="同名账户要求与处理时限" tabindex="-1">同名账户要求与处理时限 <a class="header-anchor" href="#同名账户要求与处理时限" aria-label="Permalink to &quot;同名账户要求与处理时限&quot;">​</a></h2><ul><li>转账银行账户名必须与长桥证券账户名<strong>同名</strong>，不可使用他人账户，否则退款费用由客户自行承担</li><li>FPS 资金即时转入收款账户，但需经人工审批后才存入证券账户</li><li>银行通知「已汇出」不等于长桥已收款，资金到达后需结算与审批</li><li>香港节假日不处理汇款业务，请预留时间</li><li>不接受直接存入现金</li></ul>',12)])])}const P=a(o,[["render",i]]);export{b as __pageData,P as default};
